:is(.mes_edit, .mes_copy, .mes_translate, .sd_message_gen, .mes_narrate,
    .mes_prompt, .mes_hide, .mes_unhide, .mes_media_gallery, .mes_media_list,
    .mes_embed, .mes_swipe_picker, .mes_create_bookmark, .mes_bookmark,
    .mes_create_branch, .extraMesButtonsHint, .mes_ghost,
    .mes_edit_done, .mes_edit_copy, .mes_edit_add_reasoning, .mes_edit_delete,
    .mes_edit_up, .mes_edit_down, .mes_edit_cancel,
    .mes_reasoning_arrow, .mes_reasoning_edit_done, .mes_reasoning_delete,
    .mes_reasoning_edit_cancel, .mes_reasoning_close_all, .mes_reasoning_copy,
    .mes_reasoning_edit,
    .swipe_left, .swipe_right,
    #send_but, #options_button, #extensionsMenuButton, #mes_continue,
    #mes_impersonate, #mes_stop,
    #leftNavDrawerIcon, #API-status-top, #WIDrawerIcon, #rightNavDrawerIcon,
    .drawer-icon.fa-font, .drawer-icon.fa-user-cog, .drawer-icon.fa-panorama,
    .drawer-icon.fa-cubes, .drawer-icon.fa-face-smile,
    .inline-drawer-icon.down, .inline-drawer-icon.up,
    .mes_timer, .tokenCounterDisplay)::before {
    content: '' !important;
    display: inline-block;
    flex: 0 0 auto;
    width: var(--pl-s, 18px);
    height: var(--pl-s, 18px);
    background-color: currentColor;
    -webkit-mask-image: var(--pl-i);
    -webkit-mask-size: contain;
    -webkit-mask-repeat: no-repeat;
    -webkit-mask-position: center;
    mask-image: var(--pl-i);
    mask-size: contain;
    mask-repeat: no-repeat;
    mask-position: center;
}

.mes_edit, .mes_reasoning_edit { --pl-i: var(--i-edit); }
.mes_copy, .mes_edit_copy, .mes_reasoning_copy { --pl-i: var(--i-copy); }
