.mes_edit_add_reasoning { --pl-i: var(--i-bulb); }
.mes_edit_delete, .mes_reasoning_delete { --pl-i: var(--i-trash); }
.mes_edit_up { --pl-i: var(--i-chev-u); }
.mes_edit_down { --pl-i: var(--i-chev-d); }
.mes_edit_cancel, .mes_reasoning_edit_cancel { --pl-i: var(--i-x); }
.mes_reasoning_arrow { --pl-i: var(--i-chev-u); --pl-s: 14px; }
.mes_reasoning_close_all { --pl-i: var(--i-min); }
