.swipe_right { --pl-i: var(--i-chev-r); --pl-s: 16px; }
#send_but { --pl-i: var(--i-send); }
#options_button { --pl-i: var(--i-menu); }
#extensionsMenuButton { --pl-i: var(--i-spark); }
#mes_continue { --pl-i: var(--i-arr-r); }
#mes_impersonate { --pl-i: var(--i-user); }
#mes_stop { --pl-i: var(--i-stop); }
#leftNavDrawerIcon { --pl-i: var(--i-sliders); }
