.drawer-icon.fa-font { --pl-i: var(--i-type); }
#WIDrawerIcon { --pl-i: var(--i-book); }
.drawer-icon.fa-user-cog { --pl-i: var(--i-gear); }
.drawer-icon.fa-panorama { --pl-i: var(--i-img); }
.drawer-icon.fa-cubes { --pl-i: var(--i-box); }
.drawer-icon.fa-face-smile { --pl-i: var(--i-smile); }
