#chat .mes .mes_buttons .mes_button,
#chat .mes .extraMesButtons > div { --pl-s: 16px; }
#chat .mes .mes_edit_buttons .menu_button { --pl-s: 15px; }
.mes_reasoning_actions > div { --pl-s: 14px; }
#send_but, #options_button, #extensionsMenuButton,
#mes_continue, #mes_impersonate, #mes_stop { --pl-s: 20px; }
#top-settings-holder .drawer-icon,
#top-bar .drawer-icon { --pl-s: 21px; }

.fa-solid, .fa-regular, .fa-classic, .fas, .far,
[class*="fa-"]:not(.fa-brands):not(.fab)::before {
    font-family: 'Font Awesome 6 Free' !important;
}
.fa-brands, .fab {
    font-family: 'Font Awesome 6 Brands' !important;
}

body {
    font-family: var(--pl-font-ui);
    -webkit-font-smoothing: antialiased;
}

#bg1, #bg_custom {
    filter: brightness(.58) saturate(.9);
}

body::after {
    content: '';
    display: var(--pl-tex-display, none);
    position: fixed;
    inset: 0;
    pointer-events: none;
    z-index: 9998;
    background-image: var(--pl-tex, none);
    background-size: var(--pl-tex-size, 300px 300px);
    background-repeat: repeat;
    opacity: var(--pl-tex-op, 0);
    mix-blend-mode: var(--pl-tex-blend, normal);
}

#chat {
    border: none !important;
    background: transparent !important;
}

#chat .mes {
    --pl-card-w: min(100%, 440px);
    display: flex !important;
    flex-direction: column !important;
    align-items: center !important;
    position: relative;
    width: auto !important;
    background: var(--pl-glass) !important;
    backdrop-filter: blur(16px);
    -webkit-backdrop-filter: blur(16px);
    border: 1px solid var(--pl-line) !important;
    border-radius: var(--pl-r-card);
    padding: 12px 12px 12px !important;
    margin: 0 6px 14px !important;
    box-shadow: 0 12px 34px rgba(var(--pl-shadow-rgb), .38);
}

#chat .mes[is_user="true"] {
    background: var(--pl-glass-user) !important;
}

#chat .mes.last_mes {
    border-color: rgba(var(--pl-accent-rgb), .32) !important;
}

#chat .mes::after {
    content: '';
    position: absolute;
    inset: 0 26px auto;
    height: 1px;
    background: linear-gradient(90deg, transparent, rgba(255, 255, 255, .4) 35%, rgba(var(--pl-accent-rgb), .5) 70%, transparent);
    opacity: .55;
    pointer-events: none;
}

#chat .mes.last_mes[is_user="false"] {
    padding-bottom: 40px !important;
}

#chat .mes .del_checkbox {
    position: absolute !important;
    left: 12px;
    top: 12px;
    z-index: 30;
}

#chat .mes .mes_block {
    display: flex !important;
    flex-direction: column;
    width: 100% !important;
    min-width: 0;
    max-width: 100% !important;
    padding: 0 !important;
    margin: 0 !important;
    gap: 7px;

    position: relative !important;
    z-index: 3 !important;
    overflow: visible !important;
}

#chat .mes .mesAvatarWrapper {
    width: var(--pl-card-w) !important;
    max-width: 100%;
    height: auto !important;
    min-height: 0 !important;
    margin: 0 !important;
    padding: 0 !important;
    display: block !important;
    position: relative;
    z-index: 2;
}

#chat .mes.last_mes .mesAvatarWrapper {
    padding-bottom: 0 !important;
}

#chat .mes .mesAvatarWrapper .avatar {
    width: 100% !important;
    height: auto !important;
    aspect-ratio: 1 / 1;
    min-width: 0 !important;
    min-height: 0 !important;
    max-width: 100% !important;
    max-height: none !important;
    border-radius: var(--pl-r) !important;
    overflow: hidden;
    position: relative;
    background: transparent !important;
    border: none !important;
    box-shadow: 0 8px 22px rgba(var(--pl-shadow-rgb), .3);
}

#chat .mes .mesAvatarWrapper .avatar img {
    width: 100% !important;
    height: 100% !important;
    min-width: 0 !important;
    min-height: 0 !important;
    max-width: 100% !important;
    max-height: 100% !important;
    object-fit: cover;
    object-position: center 16%;
    border: none !important;
    border-radius: var(--pl-r) !important;
    filter: saturate(1.02) contrast(1.01);
    -webkit-mask-image: linear-gradient(to bottom, #000 0%, #000 var(--pl-fade-start), transparent 100%);
    mask-image: linear-gradient(to bottom, #000 0%, #000 var(--pl-fade-start), transparent 100%);
    -webkit-mask-repeat: no-repeat;
    mask-repeat: no-repeat;
    -webkit-mask-size: 100% 100%;
    mask-size: 100% 100%;
}

#chat .mes .mesAvatarWrapper .avatar::after {
    content: '';
    position: absolute;
    inset: 0;
    border-radius: var(--pl-r);
    background:
        linear-gradient(to bottom, rgba(8, 7, 11, .5) 0%, rgba(8, 7, 11, .1) 13%, transparent 24%),
        linear-gradient(to top, var(--pl-scrim) 0%, rgba(8, 7, 11, .55) 16%, rgba(8, 7, 11, .12) 34%, transparent 50%);
    pointer-events: none;
    z-index: 3;
}

.zoomed_avatar, .zoomed_avatar img {
    border-radius: var(--pl-r) !important;
    border-color: var(--pl-line-strong) !important;
}

#chat .mes .mesAvatarWrapper .mesIDDisplay,
#chat .mes .mesAvatarWrapper .mes_timer,
#chat .mes .mesAvatarWrapper .tokenCounterDisplay {
    position: absolute !important;
    top: 11px;
    margin: 0 !important;
    z-index: 6;
    display: inline-flex;
    align-items: center;
    gap: 3px;
    font-family: var(--pl-font-ui) !important;
    font-weight: 600;
    font-size: 11px !important;
    letter-spacing: .3px;
    line-height: 1 !important;
    padding: 4px 8px !important;
    color: #ece4ee !important;

    opacity: var(--pl-meta-op) !important;
    text-shadow: var(--pl-meta-ts) !important;
    background: var(--pl-chip-bg);
    border: 1px solid rgba(255, 255, 255, .17);
    border-radius: 999px;
    backdrop-filter: blur(7px);
    -webkit-backdrop-filter: blur(7px);
}

#chat .mes .mesAvatarWrapper .mesIDDisplay {
    left: 11px;
    right: auto;
    font-variant-numeric: tabular-nums;
}

#chat .mes .mesAvatarWrapper .tokenCounterDisplay {
    right: 11px;
    left: auto;
}
#chat .mes .mesAvatarWrapper .mes_timer {
    right: 11px;
    left: auto;
    top: 39px;
}

#chat .mes .mesAvatarWrapper .tokenCounterDisplay:empty ~ .mes_timer,
#chat .mes .mesAvatarWrapper:not(:has(.tokenCounterDisplay:not(:empty))) .mes_timer {
    top: 11px;
}

#chat .mes .mesAvatarWrapper .mes_timer::before,
#chat .mes .mesAvatarWrapper .tokenCounterDisplay::before {
    opacity: .85;
}

#chat .mes .mesIDDisplay:empty,
#chat .mes .mes_timer:empty,
#chat .mes .tokenCounterDisplay:empty {
    display: none !important;
}

#chat .mes .mes_block > .ch_name {
    position: static !important;
    display: flex !important;
    justify-content: flex-end;
    align-items: center;
    flex-wrap: nowrap;
    width: 100%;
    min-height: 4px !important;
    margin: 2px 0 0 !important;
    padding: 0 !important;
    overflow: visible !important;
}

#chat .mes .ch_name > .flex1 {
    position: absolute !important;
    left: 18px !important;
    right: 18px !important;
    bottom: 100% !important;
    top: auto !important;
    margin-bottom: 16px !important;
    display: flex !important;
    flex: 0 0 auto !important;
    min-width: 0;
    align-items: flex-end !important;
    justify-content: flex-end !important;
    pointer-events: none;
    z-index: 5;
}

#chat .mes .ch_name .alignItemsBaseline {
    flex-wrap: wrap;
    align-items: baseline !important;
    column-gap: 10px;
    row-gap: 2px;
}

#chat .mes .ch_name .name_text,
body:not(.echostyle) #chat .mes .name_text {
    font-family: var(--pl-font-ui) !important;
    font-weight: 800 !important;
    font-size: 1.55em !important;
    line-height: 1.16 !important;
    letter-spacing: .2px !important;
    text-align: right !important;
    display: inline-block !important;
    visibility: visible !important;
    opacity: 1 !important;
    background: none !important;
    background-image: none !important;
    color: #ffffff !important;
    -webkit-text-fill-color: #ffffff !important;
    -webkit-text-stroke: 1.1px rgba(0, 0, 0, .92) !important;
    paint-order: stroke fill !important;
    text-shadow:
        0 0 9px rgba(255, 255, 255, .5),
        0 0 3px rgba(255, 255, 255, .45),
        0 2px 5px rgba(0, 0, 0, .95),
        0 0 2px rgba(0, 0, 0, .9) !important;
    filter: none !important;
    overflow-wrap: anywhere;
    position: relative;
    max-width: 100%;
}

.mes[is_user="true"] .ch_name .name_text {
    color: #ffffff !important;
    -webkit-text-fill-color: #ffffff !important;
}

.mes .ch_name .mes_ghost {
    color: var(--pl-pearl-soft);
    -webkit-text-fill-color: var(--pl-pearl-soft);
    filter: drop-shadow(0 1px 6px rgba(0, 0, 0, .8));
}

#chat .mes:not(.smallSysMes) .timestamp,
.mes:not(.smallSysMes) .timestamp {
    font-family: var(--pl-font-ui);
    font-weight: 500;
    font-size: .62em;
    letter-spacing: .4px;
    line-height: 1 !important;
    color: var(--pl-date-fg) !important;

    opacity: var(--pl-date-op) !important;
    padding: var(--pl-date-pad);
    background: var(--pl-date-bg);
    border: none;
    backdrop-filter: var(--pl-date-blur);
    -webkit-backdrop-filter: var(--pl-date-blur);

    -webkit-text-stroke: var(--pl-date-stroke) rgba(0, 0, 0, .8);
    paint-order: stroke fill;
    text-shadow: var(--pl-date-ts) !important;
    filter: drop-shadow(0 1px 6px rgba(0, 0, 0, .9));
}

#chat .mes.smallSysMes .timestamp,
.mes.smallSysMes .timestamp {
    color: var(--pl-muted) !important;
    opacity: .9 !important;
    background: none;
    padding: 0;
    -webkit-text-stroke: 0 !important;
    text-shadow: none !important;
    filter: none !important;
}

.mes .ch_name .mes_ghost {
    text-shadow: 0 1px 4px rgba(0, 0, 0, .85) !important;
}

#chat .mes .mes_buttons {
    position: absolute !important;
    bottom: 6px !important;
