}

#loader {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    gap: 20px;
    width: 100%;
    height: 100%;
    background-color: var(--pl-bg);
}

#loader.splash-screen #load-spinner,
#load-spinner {
    --spinner-size: 44px;
    position: relative !important;

    top: auto !important;
    left: auto !important;
    right: auto !important;
    bottom: auto !important;
    width: var(--spinner-size) !important;
    height: var(--spinner-size) !important;
    flex: 0 0 auto;
    animation: none !important;
    font-size: 0 !important;
    overflow: hidden;
    background-color: rgba(var(--pl-accent-rgb), .28);
    -webkit-mask-image: var(--i-heart-line);
    mask-image: var(--i-heart-line);
    -webkit-mask-size: contain;
    mask-size: contain;
    -webkit-mask-repeat: no-repeat;
    mask-repeat: no-repeat;
    -webkit-mask-position: center;
    mask-position: center;
    filter: drop-shadow(0 0 7px rgba(var(--pl-accent-rgb), .35));
}

#load-spinner::before {
    content: '' !important;
    position: absolute;
    inset: -60%;
    background: conic-gradient(from 0deg,
        transparent 0 58%,
        rgba(var(--pl-accent-rgb), .55) 72%,
        var(--pl-pearl) 80%,
        rgba(var(--pl-accent-rgb), .55) 88%,
        transparent 96% 100%);
    animation: pl-heart-run 2.4s linear infinite;
}

@keyframes pl-heart-run {
    to { transform: rotate(360deg); }
}

